"use client";

import { useState } from "react";
import {
  INTEREST_KEYWORDS,
  MAX_SELECTION,
  type InterestKeywordId,
  setInterestKeywords,
  setOnboardingCompleted,
} from "@/lib/interestKeywords";
import { Sparkles } from "lucide-react";

type Props = {
  onComplete?: () => void;
};

export default function InterestKeywordOnboarding({ onComplete }: Props) {
  const [selected, setSelected] = useState<InterestKeywordId[]>([]);

  const toggle = (id: InterestKeywordId) => {
    setSelected((prev) => {
      if (prev.includes(id)) return prev.filter((k) => k !== id);
      if (prev.length >= MAX_SELECTION) return prev;
      return [...prev, id];
    });
  };

  const handleConfirm = () => {
    setInterestKeywords(selected);
    setOnboardingCompleted();
    onComplete?.();
  };

  return (
    <div className="max-w-lg mx-auto py-8 px-4">
      <div className="text-center mb-8">
        <div className="inline-flex items-center justify-center w-14 h-14 rounded-full bg-skyblue/20 text-skyblue mb-4">
          <Sparkles className="w-7 h-7" />
        </div>
        <h1 className="text-2xl font-bold text-white mb-2">관심 분야를 골라 주세요</h1>
        <p className="text-gray-400 text-sm">
          선택한 키워드에 맞는 뉴스·정책만 모아서 보여 드려요. (최대 {MAX_SELECTION}개)
        </p>
      </div>

      <div className="flex flex-wrap justify-center gap-2 mb-8">
        {INTEREST_KEYWORDS.map((kw) => {
          const isSelected = selected.includes(kw.id);
          return (
            <button
              key={kw.id}
              type="button"
              onClick={() => toggle(kw.id)}
              disabled={!isSelected && selected.length >= MAX_SELECTION}
              className={`
                px-4 py-2 rounded-full text-sm font-medium transition-all
                border whitespace-nowrap
                ${isSelected
                  ? "bg-skyblue/30 border-skyblue text-skyblue"
                  : selected.length >= MAX_SELECTION
                    ? "bg-white/5 border-white/10 text-gray-500 cursor-not-allowed"
                    : "bg-white/5 border-white/20 text-gray-300 hover:bg-white/10 hover:border-white/30"
                }
              `}
            >
              {kw.label}
            </button>
          );
        })}
      </div>

      <div className="text-center">
        <p className="text-xs text-gray-500 mb-4">
          {selected.length} / {MAX_SELECTION}개 선택
        </p>
        <button
          type="button"
          onClick={handleConfirm}
          disabled={selected.length === 0}
          className="px-8 py-3 rounded-full bg-skyblue text-white font-medium disabled:opacity-50 disabled:cursor-not-allowed hover:bg-skyblue/90 transition-colors"
        >
          확인하고 시작하기
        </button>
      </div>
    </div>
  );
}
