"use client";

import { useEffect, useState } from "react";
import { Loader2, X } from "lucide-react";

interface ThemeDetailProps {
    themeKey: string;
    onClose: () => void;
}

interface NewsItem {
    title: string;
    link: string;
}

interface PolicyItem {
    title: string;
    link: string;
}

interface StockItem {
    code: string;
    name: string;
    change_rate: number;
    desc: string;
}

interface ThemeDetailData {
    theme_name: string;
    news: NewsItem[];
    policies: PolicyItem[];
    analysis: StockItem[];
}

export default function ThemeDetail({ themeKey, onClose }: ThemeDetailProps) {
    const [data, setData] = useState<ThemeDetailData | null>(null);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState<"news" | "policy" | "analysis">("news");

    useEffect(() => {
        async function fetchData() {
            setLoading(true);
            try {
                const res = await fetch(`/api/dashboard/theme/detail?theme_key=${themeKey}`);
                if (res.ok) {
                    const json = await res.json();
                    setData(json);
                }
            } catch (err) {
                console.error(err);
            } finally {
                setLoading(false);
            }
        }
        fetchData();
    }, [themeKey]);

    if (!themeKey) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in zoom-in duration-200">
            <div className="bg-[#1e293b] w-full max-w-lg rounded-2xl border border-white/10 shadow-2xl relative flex flex-col max-h-[80vh]">
                {/* Header */}
                <div className="flex justify-between items-center p-4 border-b border-white/10">
                    <h3 className="text-xl font-bold text-white">
                        {data ? data.theme_name : "로딩 중..."}
                    </h3>
                    <button onClick={onClose} className="text-gray-400 hover:text-white transition-colors">
                        <X size={24} />
                    </button>
                </div>

                {loading ? (
                    <div className="flex-1 flex justify-center items-center py-20">
                        <Loader2 className="animate-spin text-sky-400" size={32} />
                    </div>
                ) : !data ? (
                    <div className="p-8 text-center text-gray-400">데이터를 불러올 수 없습니다.</div>
                ) : (
                    <>
                        {/* Tabs */}
                        <div className="flex border-b border-white/10">
                            <button
                                onClick={() => setActiveTab("news")}
                                className={`flex-1 py-3 text-sm font-medium transition-colors border-b-2 ${activeTab === "news"
                                        ? "border-sky-400 text-sky-400"
                                        : "border-transparent text-gray-400 hover:text-white"
                                    }`}
                            >
                                뉴스
                            </button>
                            <button
                                onClick={() => setActiveTab("policy")}
                                className={`flex-1 py-3 text-sm font-medium transition-colors border-b-2 ${activeTab === "policy"
                                        ? "border-emerald-400 text-emerald-400"
                                        : "border-transparent text-gray-400 hover:text-white"
                                    }`}
                            >
                                정책
                            </button>
                            <button
                                onClick={() => setActiveTab("analysis")}
                                className={`flex-1 py-3 text-sm font-medium transition-colors border-b-2 ${activeTab === "analysis"
                                        ? "border-violet-400 text-violet-400"
                                        : "border-transparent text-gray-400 hover:text-white"
                                    }`}
                            >
                                분석(종목)
                            </button>
                        </div>

                        {/* Content Area */}
                        <div className="flex-1 overflow-y-auto p-4 min-h-0">
                            {activeTab === "news" && (
                                <ul className="space-y-3">
                                    {data.news.map((item, i) => (
                                        <li key={i} className="bg-white/5 p-3 rounded-lg hover:bg-white/10 transition-colors">
                                            <a href={item.link} target="_blank" rel="noopener noreferrer" className="block">
                                                <p className="text-sm text-white line-clamp-2">{item.title}</p>
                                            </a>
                                        </li>
                                    ))}
                                    {data.news.length === 0 && <p className="text-gray-500 text-center">관련 뉴스 없음</p>}
                                </ul>
                            )}

                            {activeTab === "policy" && (
                                <ul className="space-y-3">
                                    {data.policies.map((item, i) => (
                                        <li key={i} className="bg-emerald-900/10 border border-emerald-500/20 p-3 rounded-lg hover:bg-emerald-900/20 transition-colors">
                                            <a href={item.link} target="_blank" rel="noopener noreferrer" className="block">
                                                <p className="text-sm text-emerald-100 line-clamp-2">{item.title}</p>
                                            </a>
                                        </li>
                                    ))}
                                    {data.policies.length === 0 && <p className="text-gray-500 text-center">관련 정책 없음</p>}
                                </ul>
                            )}

                            {activeTab === "analysis" && (
                                <div className="space-y-3">
                                    {data.analysis.map((stock, i) => (
                                        <div key={i} className="bg-violet-900/10 border border-violet-500/20 p-3 rounded-lg flex justify-between items-center">
                                            <div>
                                                <div className="flex items-center gap-2">
                                                    <span className="text-white font-bold">{stock.name}</span>
                                                    <span className="text-xs text-gray-400">{stock.code}</span>
                                                </div>
                                                <p className="text-xs text-violet-200 mt-1">{stock.desc}</p>
                                            </div>
                                            <div className={`text-right font-medium ${stock.change_rate > 0 ? "text-red-400" : "text-blue-400"}`}>
                                                {stock.change_rate > 0 ? "+" : ""}{stock.change_rate}%
                                            </div>
                                        </div>
                                    ))}
                                    {data.analysis.length === 0 && <p className="text-gray-500 text-center">관련 종목 데이터 없음</p>}
                                </div>
                            )}
                        </div>
                    </>
                )}
            </div>
        </div>
    );
}
